					delta := newCost - oldCost
					if delta < 0 {
						delta = 0
					}
					timeSlack := float64(dispatch.Assigns[i].StationCurrent.TimeEnd-dispatch.Assigns[i].StationCurrent.TimeStart+1) / 1440.0
					routeLen := float64(len(dispatch.Assigns[i].Stations))
					normalizedDelta := delta / (oldCost + 1e-6)
