func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		score     float64
		delta     float64
		slackGain float64
		success   bool
	}
	const alpha = 0.7
	const beta = 0.3
	const gamma = 0.15
	for shipIDOffset, ori := range oris {
		des := dess[shipIDOffset]
		shipID := total_ship + shipIDOffset
		candidates := make([]cand, 0, dispatch.AssignsLen+1)
		bestSeedIdx := -1
		var bestSeedScore float64 = 1e18
		for i := 0; i < dispatch.AssignsLen; i++ {
			oldCost := dispatch.Assigns[i].Cost
			ok := dispatch.Assigns[i].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[i].GenRoute()
				newCost := dispatch.Assigns[i].Cost
				if newCost >= 0 {
					delta := newCost - oldCost
					if delta < 0 {
						delta = 0
					}
					timeSlack := float64(dispatch.Assigns[i].StationCurrent.TimeEnd-dispatch.Assigns[i].StationCurrent.TimeStart+1) / 1440.0
					routeLen := float64(len(dispatch.Assigns[i].Stations))
					normalizedDelta := delta / (oldCost + 1e-6)
					slackScore := timeSlack / (routeLen + 1.0)
					score := alpha*normalizedDelta - beta*slackScore + gamma*(1.0/(routeLen+1.0))
					candidates = append(candidates, cand{idx: i, delta: delta, slackGain: slackScore, score: score, success: true})
					seedCand := normalizedDelta - 0.5*slackScore
					if seedCand < bestSeedScore {
						bestSeedScore = seedCand
						bestSeedIdx = i
					}
				}
			}
			dispatch.Assigns[i].RemoveShip(shipID)
			dispatch.Assigns[i].GenRoute()
		}
		inserted := false
		if len(candidates) > 0 {
			bestIdx := 0
			bestVal := candidates[0].score
			secondBest := 1e18
			for j := 1; j < len(candidates); j++ {
				if candidates[j].score < bestVal {
					secondBest = bestVal
					bestVal = candidates[j].score
					bestIdx = j
				} else if candidates[j].score < secondBest {
					secondBest = candidates[j].score
				}
			}
			regret := 0.0
			if secondBest < 1e17 {
				regret = secondBest - bestVal
			}
			finalPick := bestIdx
			if regret > 0 {
				penaltyWeight := 0.8
				for j := 0; j < len(candidates); j++ {
					adjScore := candidates[j].score - penaltyWeight*candidates[j].slackGain
					if adjScore < candidates[finalPick].score-penaltyWeight*candidates[finalPick].slackGain {
						finalPick = j
					}
				}
			}
			chosen := candidates[finalPick]
			ok := dispatch.Assigns[chosen.idx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[chosen.idx].GenRoute()
				if dispatch.Assigns[chosen.idx].Cost >= 0 {
					inserted = true
				} else {
					dispatch.Assigns[chosen.idx].RemoveShip(shipID)
					dispatch.Assigns[chosen.idx].GenRoute()
				}
			}
		}
		if !inserted {
			seedOk := false
			if bestSeedIdx >= 0 {
				ok := dispatch.Assigns[bestSeedIdx].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[bestSeedIdx].GenRoute()
					if dispatch.Assigns[bestSeedIdx].Cost >= 0 {
						seedOk = true
						inserted = true
					} else {
						dispatch.Assigns[bestSeedIdx].RemoveShip(shipID)
						dispatch.Assigns[bestSeedIdx].GenRoute()
					}
				}
			}
			if !seedOk && dispatch.AssignsLen < MAXASSIGNS {
				assignPtr := &dispatch.Assigns[dispatch.AssignsLen]
				ok := assignPtr.AddShip(shipID, ori, des)
				if ok {
					assignPtr.GenRoute()
					if assignPtr.Cost >= 0 {
						dispatch.AssignsLen++
						inserted = true
					} else {
						assignPtr.RemoveShip(shipID)
						assignPtr.GenRoute()
					}
				}
			}
			if !inserted && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
				assignPtr := &dispatch.Assigns[dispatch.AssignsLen-1]
				assignPtr.AddShip(shipID, ori, des)
				assignPtr.GenRoute()
				inserted = true
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
